   208	/* connect jump */
   209	void be_code_conjump(bfuncinfo *finfo, int *list, int jmp)
   210	{
   211	    if (jmp == NO_JUMP) {
   212	        return;
   213	    }
   214	    if (*list == NO_JUMP) {
   215	        *list = jmp;
   216	    } else {
   217	        int next, l = *list;
   218	        while ((next = (get_jump(finfo, l))) != NO_JUMP) {
   219	            l = next;
   220	        }
   221	        setjump(finfo, l, jmp);
   222	    }
   223	}
